import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';
import { ActivityIndicator, Alert, Button, SafeAreaView, StyleSheet, Text, TextInput, View } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AUTH_TOKEN_KEY = '@auth_token';
const USER_DATA_KEY = '@user_data';

const AuthContext = createContext(null);

export function useAuth() {
  return useContext(AuthContext);
}

async function persistAuth(token, user) {
  await AsyncStorage.multiSet([
    [AUTH_TOKEN_KEY, token],
    [USER_DATA_KEY, JSON.stringify(user)],
  ]);
}

async function clearAuth() {
  await AsyncStorage.multiRemove([AUTH_TOKEN_KEY, USER_DATA_KEY]);
}

async function loadAuth() {
  const [[, token], [, userJson]] = await AsyncStorage.multiGet([AUTH_TOKEN_KEY, USER_DATA_KEY]);
  const user = userJson ? JSON.parse(userJson) : null;
  return { token: token || null, user };
}

async function fakeLoginApi(email, password) {
  await new Promise((r) => setTimeout(r, 900));
  if (!email || !password) {
    throw new Error('Email and password are required.');
  }
  if (password.length < 4) {
    throw new Error('Invalid credentials.');
  }
  return {
    token: `token_${Date.now()}`,
    user: {
      id: 'user_1',
      name: 'Demo User',
      email,
    },
  };
}

function AuthProvider({ children }) {
  const [isBootstrapping, setIsBootstrapping] = useState(true);
  const [token, setToken] = useState(null);
  const [user, setUser] = useState(null);

  useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        const saved = await loadAuth();
        if (mounted) {
          setToken(saved.token);
          setUser(saved.user);
        }
      } catch (e) {
        await clearAuth();
      } finally {
        if (mounted) setIsBootstrapping(false);
      }
    })();
    return () => {
      mounted = false;
    };
  }, []);

  const signIn = async (email, password) => {
    const result = await fakeLoginApi(email, password);
    await persistAuth(result.token, result.user);
    setToken(result.token);
    setUser(result.user);
  };

  const signOut = async () => {
    await clearAuth();
    setToken(null);
    setUser(null);
  };

  const value = useMemo(
    () => ({
      isBootstrapping,
      token,
      user,
      isAuthenticated: !!token,
      signIn,
      signOut,
    }),
    [isBootstrapping, token, user]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

function LoginScreen() {
  const auth = useAuth();
  const [email, setEmail] = useState('demo@example.com');
  const [password, setPassword] = useState('1234');
  const [loading, setLoading] = useState(false);

  const handleLogin = async () => {
    try {
      setLoading(true);
      await auth.signIn(email.trim(), password);
    } catch (e) {
      Alert.alert('Login Failed', e.message || 'Unable to sign in.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Sign In</Text>
        <TextInput
          style={styles.input}
          placeholder="Email"
          autoCapitalize="none"
          keyboardType="email-address"
          value={email}
          onChangeText={setEmail}
        />
        <TextInput
          style={styles.input}
          placeholder="Password"
          secureTextEntry
          value={password}
          onChangeText={setPassword}
        />
        <Button title={loading ? 'Signing in...' : 'Sign In'} onPress={handleLogin} disabled={loading} />
      </View>
    </SafeAreaView>
  );
}

function HomeScreen() {
  const auth = useAuth();

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Welcome</Text>
        <Text style={styles.text}>User ID: {auth.user?.id}</Text>
        <Text style={styles.text}>Name: {auth.user?.name}</Text>
        <Text style={styles.text}>Email: {auth.user?.email}</Text>
        <View style={{ height: 16 }} />
        <Button title="Sign Out" onPress={auth.signOut} />
      </View>
    </SafeAreaView>
  );
}

function BootstrapScreen() {
  return (
    <SafeAreaView style={styles.container}>
      <ActivityIndicator size="large" />
    </SafeAreaView>
  );
}

function AppNavigator() {
  const auth = useAuth();

  if (auth.isBootstrapping) return <BootstrapScreen />;
  return auth.isAuthenticated ? <HomeScreen /> : <LoginScreen />;
}

export default function App() {
  return (
    <AuthProvider>
      <AppNavigator />
    </AuthProvider>
  );
}

